}

hr {
	border: none;
	margin: 1em 0;
	padding: 2px 10px;
}

hr:after {
	background-color: silver;
	content: '';
	display: block;
	height: 1px;
	line-height: 2px;
}

ul,
ol {
	padding-left: 30px;

}

ul li p, ol li p {
	margin-bottom: 0.2em;
}

ul li:last-child p, ol li:last-child p {
	margin-bottom: 1em;
}


u {
	text-decoration: underline;
}

strong {
	font-weight: bold;
}

em {
	font-style: italic;
}

blockquote {
	border-left: 3px solid #eee;
	margin-left: 0;
	margin-right: 0;
	padding-left: 1em;
}

img {
	cursor: default;
	max-width: 100%;
	object-fit: scale-down;
}

sup,
sub {
	line-height: 0;
}

/* Tables */

table {
	border: 1px solid #eee;
	border-collapse: initial;
	border-spacing: 0;
	border-width: 0 thin thin 0;
	margin: 0;
	overflow: hidden;
	/* page-break-inside: avoid; */
	/* table-layout: fixed; */
	width: 100%;
	margin: 1em 0;
}

th,
td {
	border: 1px solid #eee;
	box-sizing: border-box;
	/*width: 200px;*/
	padding: 2px 5px;
	position: relative;
	vertical-align: top;
}

th {
	background-color: hsl(220,18%,81.8%); /*${lightenBy('colorPrimary', 0.7)};*/
}

.tableWrapper {
	overflow-x: auto;
}

span.comment {
	border-bottom: 2px solid #ffab20;
	border-radius: 3px 3px 0 0;
}

code {
	font-family: monospace;
}

.small-caps {
	font-variant: small-caps;
}

a {
	color: blue;
}

/* == Math Nodes ======================================== */

.math-node {
	cursor: auto;
	font-family: 'Consolas', 'Ubuntu Mono', monospace;
	font-size: 0.95em;
	min-height: 1em;
	min-width: 1em;


}

.math-node 	.ProseMirror {
	background: #eee;
	box-shadow: none;
	color: rgb(132, 33, 162);
	min-height: 100%;
	padding: 0;
}

.math-node.empty-math .math-render::before {
	color: red;
	content: '(empty)';
}

.math-node .math-render.parse-error::before {
	color: red;
	content: '(math error)';
	cursor: help;
}

/* -- Inline Math --------------------------------------- */

math-inline {
	display: inline;
	white-space: nowrap;
}

math-inline .math-render {
	cursor: pointer;
	display: inline-block;
	font-size: 0.85em;
}

math-inline .math-src .ProseMirror {
	display: inline;
}

math-inline .math-src::after,
math-inline .math-src::before {
	color: #b0b0b0;
	content: '$';
}

/* -- Block Math ---------------------------------------- */

math-display {
	display: block;
}

math-display .math-render {
	display: block;
	text-align: center;
}

math-display.ProseMirror-selectednode {
	background-color: #eee;
}

math-display .math-src .ProseMirror {
	display: block;
	width: 100%;
}

math-display .math-src::after,
math-display .math-src::before {
	color: #b0b0b0;
	content: '$$';
	text-align: left;
}

math-display .katex-display {
	margin: 0;
}

/* -- Other Math ---------------------------------------- */

.math-node.ProseMirror-selectednode {
	outline: none;
}

.math-node .math-src {
	color: rgb(132, 33, 162);
	display: none;
	tab-size: 4;
}

.math-node.ProseMirror-selectednode .math-src {
	display: flex;
}

.math-node.ProseMirror-selectednode .math-render {
	display: none;
}

.fundingsource:before {
	content: 'Funding source: ';
	font-weight: bold;
}

.awardid:before {
	content: 'Award ID: ';
	font-weight: bold;
}

.fundingstatement:before {
	content: "Funding statement: ";
	font-weight: bold;
