	color: var(--color-main);
	text-decoration: underline;
	text-underline-offset: 3px;
	text-decoration-color: var(--color-main-light);
}

.content p {
	text-align: justify;
}

#researchLevel {
	text-transform: uppercase;
	font-family: serif;
	font-size: 1.3em;
	color: var(--color-main);
	letter-spacing: 0.2ch;
	width: max-content;
	display: inline-block;
	margin-top: 1.4em;
	margin-bottom: 0.4em;
	font-size: 1.6em;
}

#topicList {
	display: inline;
	width: max-content;
	color: var(--color-main);
	list-style-type: none;
	text-align: right;
	padding: 0;
	margin-left: 0;
	margin-bottom: 0;
	margin-left: auto;
	text-align: right;
}

#topicList li {
	margin-right: 2ch;
	margin-left: 3ch;
	display: inline-block;
	color: var(--color-main-dark);
	/*experimental */
}
#topicList li::before {
	content: ' #';
}
h1.title {
	margin-top: 0;
	font-size: 1.5em;
	margin-top: 0;
	line-height: 1.3;
	font-weight: 600;
}

.formattedAuthors,
.formattedAffiliations {
	font-size: 1em;
	text-align: right;
	margin-top: 0;
	line-height: 1.3;
	margin-bottom: 0;
}
.formattedAuthors {
	font-weight: 600;
	margin-bottom: 0.5em;
}

.formattedAffiliations {
	margin-left: 30mm;
}

.formattedAuthors sup {
	color: var(--color-main);
	font-size: 0.8em;
}

:is(.formattedAuthors, .formattedAffiliations) ul {
	list-style-type: none;
	margin: 0;
	padding: 0;
}

:is(.formattedAuthors, .formattedAffiliations) ul li {
	display: inline;
}

.formattedAffiliations {
	margin-top: 0;
	font-size: 0.9em;
	margin-bottom: 1em;
}

h2,
h3,
h4,
h5,
h6 {
	margin-top: 1em;
	margin-bottom: 0.3em;
	font-weight: 700;
	break-after: avoid;
	color: var(--color-main);
}
h2 {
	font-size: 1.4em;
	margin-top: 2em;
}

h3 {
	font-size: 1.4em;
	font-weight: 500;
}

/* h4 {
} */

h5 {
	text-transform: uppercase;
	font-size: 1em;
	text-decoration: underline;
}

h6 {
	font-size: 1em;
	text-decoration: underline;
}
/* footnote {
  display: none;
} */
footnote, .footnote {
	float: footnote;
	font-size: 0.8em;
	padding-top: 0.5em;

	/* margin-left: 40mm; */
	/* margin-top: 1em; */
	/* font-size: 12px; */
}

footnote a, .footnote a {
	word-break: break-all;
}

::footnote-call {
	color: var(--color-main);
	font-weight: 500;
}

::footnote-marker {
	content: counter(footnote-marker) '. ';
	/* color: var(--color-main-dark); */
	font-weight: 500;
	line-height: 0;
}

/* footnote debugger */
/* [data-has-notes] {
  color: orange;
} */

table {
	border-collapse: collapse;
	font-size: 0.8em;
	break-inside: avoid;
}
table :is(td, tr) {
	padding: 0;
	margin: 0;
}

table p {
	margin: 0;
	padding: 0.3em 2ch;
	line-height: 1.2;
}

table thead th {
	background: var(--color-main-light);
}

table tr {
	border-bottom: 1px solid var(--color-main);
	/* break-inside: avoid; */
}

/*figure*/

main {
	counter-reset: figure;
}

figure {
	break-inside: avoid;
	display: block;
	counter-increment: figure;
	/* width: 100%; */
	display: block;
	height: auto;
	margin: 0.5em 8ch;
	/* border: 2px solid var(--color-main); */
	padding: 1em 2ch;
	/* column-span: all; */
}

figure img {
	margin: auto;
}

figure[data-split-to] {
	border-bottom: 1px solid transparent !important;
}
figure[data-split-from] {
	border-top: 1px solid transparent !important;
}

img {
	width: 100%;
	height: auto;
	max-height: 40em;
	object-fit: contain;
	object-position: top left;
}
figcaption {
	font-size: 0.9em;
	margin-top: 1em;
}
figcaption em {
	font-style: normal;
}

.doi {
	string-set: doi content(text);
	margin: 0;
	text-align: right;
	width: 100%;
	line-height: 1;
	display:none;
}


.marginData {
	font-size: 10px;
}
.marginData h4 {
	font-weight: 300;
}

.marginData {
	/* margin-left: calc(var(--pagedjs-margin-left) * -1); */
	/* margin-right: calc(var(--pagedjs-margin-right) * -1); */
	/* padding-right: var(--pagedjs-margin-right); */
	/* padding-left: var(--pagedjs-margin-left); */
	/* background: var(--color-main-light); */
	/* padding-top: 0.4em; */
