}
.marginData h4 {
	text-decoration: none;
	margin: 0;
}

.marginData p {
	margin: 0.5ch 0;
}

.marginData > section {
	display: grid;
	align-items: baseline;
	grid-gap: 0 4ch;
	grid-template-columns: max-content 1fr;
}
.marginData .date {
	display: grid;
	grid-template-columns: repeat(3, 1fr);
}

.marginData .date > div :is(h4, p) {
	margin-right: 1.4ch;
	display: inline;
