.marginData {
	/* columns: 2; */
	gap: 4ch;
	font-size: 0.9em;
	margin: 0 10ch 0 10ch;
}

.content p {
	margin-top: 0;
}

a {
	white-space: pre-wrap;
	overflow-wrap: break-word;
	color: var(--color-main);
}

.abstract {
	font-size:1em;
	font-weight:500;
	background: var(--color-main-light);
	margin-left: calc((var(--pagedjs-margin-left) + 10ch) * -1);
	margin-right: calc((var(--pagedjs-margin-right) + 10ch) * -1);
	padding: 1em calc(10ch + var(--pagedjs-margin-right)) 1em calc(10ch + var(--pagedjs-margin-left));
	display: block;
	margin-bottom: 4ch;
}

.abstract h2:first-child {
	margin-top: 0;
}

@page {
	size: letter;
	margin: 18mm 14mm 26mm 14mm;

	@footnote {
		float: bottom;
		font-size: 10px;
		margin: 0 10ch;
	}
}

@page :first {
	margin-top: 30mm;
	@top-left-corner {
		border: 0;
		content: none;
	}
	@top-left {
		content: none;
	}
	@top-right {
		content: none;
	}
}

.logo {
	width: 30mm;
	top: -28mm;
	position: absolute;
	padding-top: 2em;
	padding-right: 3ch;
	background: white;
}



.titlepage::before {
	content: string(journalSlug); 
	font-size: 0.8em;
	color: white;
	margin-left: calc(var(--pagedjs-margin-left) * -1);
	margin-right: calc(var(--pagedjs-margin-right) * -1);
	background: var(--color-main);
	display: block;
	padding-top: 0.4em;
	padding-bottom: 0.3em;
	line-height: 1.2;
	padding-right: 5ch;
	text-align: right;
}

.titlepage[data-split-from]::before {
	content: none;
}

#researchLevel {
	string-set: researchLevel content(text);
}

.title {
	string-set: title content(text);
}

#journalTitle {
	string-set: journalTitle content(text);
	display: none;
}

#journalSlug {
	string-set: journalSlug content(text);
	display: none;
}

@page {
	@top-left-corner {
		content: ' ';
		border-bottom: 3px solid var(--color-main);
		width: 100%;
		display: block;
		width: var(--pagedjs-width);
		top: 3em;
		position: absolute;
	}
	@top-left {
		font-size: 10px;
		color: var(--color-grey);
		margin-top: -2em;
		content: string(researchLevel) ' — ' string(title);
		/* write-space: nowrap; */
	}
	@top-right {
		font-size: 10px;
		color: var(--color-grey);
		margin-top: -2em;
		content: string(journalTitle);
		color: var(--color-main);
	}
	@bottom-left-corner {
		content: ' ';
		border-bottom: 3px solid var(--color-main);
		width: 100%;
		display: block;
		width: var(--pagedjs-width);
		bottom: 5em;
		position: absolute;
	}
	@bottom-left {
		font-size: 10px;
		color: var(--color-grey);
		margin-top: 4em;
		content: string(doi) ' — ' string(title);
	}
	@bottom-right {
		font-size:10px;
		margin-top: 4em;
		content: counter(page) ' of ' counter(pages);
		color: var(--color-grey);
		width: 30ch;
	}
}

